import{_ as i,o as s,c as a,a0 as p}from"./chunks/framework.Dx25mwie.js";const c=JSON.parse('{"title":"Go-Spring 实战第 22 课 —— 日志输出与格式化：Appender、Layout 与 Encoder","description":"","frontmatter":{"head":[]},"headers":[],"relativePath":"docs/8.wechat-series/22-logging-output-formatting.md","filePath":"docs/8.wechat-series/22-logging-output-formatting.md"}'),n={name:"docs/8.wechat-series/22-logging-output-formatting.md"};function t(l,e,o,d,h,r){return s(),a("div",null,[...e[0]||(e[0]=[p(`<h1 id="go-spring-实战第-22-课-——-日志输出与格式化-appender、layout-与-encoder" tabindex="-1">Go-Spring 实战第 22 课 —— 日志输出与格式化：Appender、Layout 与 Encoder <a class="header-anchor" href="#go-spring-实战第-22-课-——-日志输出与格式化-appender、layout-与-encoder" aria-label="Permalink to &quot;Go-Spring 实战第 22 课 —— 日志输出与格式化：Appender、Layout 与 Encoder&quot;">​</a></h1><p>上一篇咱们介绍了日志的路由与调度。Tag 会根据精确规则、层级通配和 Root Logger 找到对应的 Logger；Logger 完成级别过滤以后，再根据具体类型同步、异步或者直接处理 Event。组合式 Logger 通过 <code>AppenderRef</code> 分发 Event，集成式 Logger 则在内部使用相应的 Appender。</p><p>Event 进入 Appender 以后，日志处理还需要回答三个问题：写到哪里、整条日志采用什么格式、每个 Field 怎样转换成字节。为了解决这三个问题，Go-Spring 分别使用 Appender、Layout 和 Encoder 承担对应的职责；它们共同组成了日志的输出阶段。</p><h2 id="appender" tabindex="-1">Appender <a class="header-anchor" href="#appender" aria-label="Permalink to &quot;Appender&quot;">​</a></h2><p>我们可以把 Appender 理解为日志输出目标的抽象。它负责接收 Event、管理输出资源并完成实际写入，但不负责选择 Logger，也不决定 Event 是否能够通过级别过滤。</p><p>Appender 可能会持有文件句柄、连接或者其他资源，因此需要通过 <code>Start</code> 和 <code>Stop</code> 参与日志系统的生命周期。与此同时，<code>ConcurrentSafe</code> 会声明它能否被多个 goroutine 并发调用；日志系统会据此检查组合式 Logger 与 Appender 的连接是否合法。</p><p>Go-Spring 内置了四种 Appender：<code>DiscardAppender</code>、<code>ConsoleAppender</code>、<code>FileAppender</code>、<code>RollingFileAppender</code>。</p><h3 id="discardappender" tabindex="-1">DiscardAppender <a class="header-anchor" href="#discardappender" aria-label="Permalink to &quot;DiscardAppender&quot;">​</a></h3><p><code>DiscardAppender</code> 接收 Event，但不产生实际输出。</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.discard.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = DiscardAppender</span></span></code></pre></div><p>它通常用于组合式 Logger 的某个输出分支。虽然它与上一课介绍的 <code>DiscardLogger</code> 都会丢弃日志，但两者所在的层次不同：<code>DiscardLogger</code> 在 Logger 层直接结束处理；<code>DiscardAppender</code> 则仍然是一个可以被 <code>AppenderRef</code> 引用的输出目标。</p><h3 id="consoleappender" tabindex="-1">ConsoleAppender <a class="header-anchor" href="#consoleappender" aria-label="Permalink to &quot;ConsoleAppender&quot;">​</a></h3><p><code>ConsoleAppender</code> 将日志写入标准输出。本地开发时可以直接查看输出；在容器环境中，日志采集系统也可以统一读取标准输出。</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.console.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = ConsoleAppender</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.console.layout.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = TextLayout</span></span></code></pre></div><p>它不持有需要关闭的文件资源，同时也支持并发调用。至于最终输出普通文本还是 JSON，则由内部配置的 Layout 决定。</p><h3 id="fileappender" tabindex="-1">FileAppender <a class="header-anchor" href="#fileappender" aria-label="Permalink to &quot;FileAppender&quot;">​</a></h3><p><code>FileAppender</code> 持续向指定文件追加日志，适合日志量较小、文件生命周期由外部系统管理，或者只需要固定文件输出的场景。</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.file.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = FileAppender</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.file.dir</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = ./logs</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.file.file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = app.log</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.file.layout.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = JSONLayout</span></span></code></pre></div><p><code>FileAppender</code> 不负责自动切换文件，也不负责清理历史文件；它会在 <code>Start</code> 阶段打开文件，在 <code>Stop</code> 阶段关闭文件。</p><p>需要注意的是，<code>FileAppender</code> 不会自动创建 <code>dir</code> 对应的目录。因此，如果目录不存在或者没有写入权限，Appender 就会在日志系统启动阶段返回错误。</p><h3 id="rollingfileappender" tabindex="-1">RollingFileAppender <a class="header-anchor" href="#rollingfileappender" aria-label="Permalink to &quot;RollingFileAppender&quot;">​</a></h3><p>对于长期运行的服务，单个日志文件会不断增长，通常需要按时间滚动文件，并定期清理历史内容。这类场景可以使用 <code>RollingFileAppender</code>。</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.rolling.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = RollingFileAppender</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.rolling.dir</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = ./logs</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.rolling.file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = app.log</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.rolling.interval</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 1h</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.rolling.maxAge</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 168h</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.rolling.syncLock</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = false</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.rolling.layout.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = JSONLayout</span></span></code></pre></div><p><code>interval</code> 表示文件滚动周期，<code>maxAge</code> 表示历史文件的保留时间。不过，历史文件清理依赖后续滚动触发，并不是到达 <code>maxAge</code> 后立即删除；应用启动时也不会单独扫描和清理旧文件。</p><p><code>RollingFileAppender</code> 内部的 <code>RollingFileWriter</code> 不是并发安全的。如果它连接在 <code>SyncLogger</code> 后面，多个业务 goroutine 可能会同时调用 Appender，此时需要设置 <code>syncLock=true</code>。反过来，如果它连接在 <code>AsyncLogger</code> 后面，Event 会由后台 goroutine 顺序写入，通常就可以保持 <code>syncLock=false</code>。</p><p>正因为 <code>SyncLogger</code> 可能会并发调用 Appender，所以日志系统在创建它时，会检查所引用的 Appender 是否支持并发调用。如果 Appender 不是并发安全的，日志配置就会在初始化阶段失败，而不会把并发问题留到运行期。</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>Appender 决定日志写到哪里，Layout 则决定一条完整的日志长什么样。它会接收 Event，然后把格式化结果写入 <code>Writer</code>。</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Layout</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> interface</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">	EncodeTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Event</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">w</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Writer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>一个 Event 中不仅包含业务 Field，还包含 Level、Time、File、Line、Tag 和上下文信息。至于保留哪些内容、按照什么顺序组织，以及采用什么整体结构，则都由 Layout 决定。</p><p>Go-Spring 内置了 <code>TextLayout</code> 和 <code>JSONLayout</code>。两者处理的是同一个 Event，只是最终的表现形式不同。</p><p>它们都会处理下面这些公共信息：</p><ul><li><code>level</code>：日志级别。</li><li><code>time</code>：日志时间。</li><li><code>fileLine</code>：调用文件和行号。</li><li><code>tag</code>：日志标签。</li><li>上下文字符串和上下文字段。</li><li>调用点传入的业务 Field。</li></ul><p>两种 Layout 都可以通过 <code>fileLineMaxLength</code> 限制文件路径的展示长度。如果路径超过了限制，Layout 会截断前面的部分，只保留更接近文件名和行号的内容。</p><h3 id="textlayout" tabindex="-1">TextLayout <a class="header-anchor" href="#textlayout" aria-label="Permalink to &quot;TextLayout&quot;">​</a></h3><p><code>TextLayout</code> 生成便于人阅读的单行文本：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[INFO][2026-06-05T10:30:00.000][order.go:42] _biz_order_create||order_id=10001||msg=订单创建完成</span></span></code></pre></div><p>它会先写入级别、时间、调用位置和 Tag，再使用 <code>||</code> 分隔上下文信息与业务 Field。顶层 Field 使用 <code>key=value</code> 形式表达；数组和嵌套对象则仍然使用 JSON 结构。</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.console.layout.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = TextLayout</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.console.layout.fileLineMaxLength</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 48</span></span></code></pre></div><p>这种格式既保留了结构化字段，整体上又是一行面向人的普通文本，因此更适合本地开发和直接阅读。</p><h3 id="jsonlayout" tabindex="-1">JSONLayout <a class="header-anchor" href="#jsonlayout" aria-label="Permalink to &quot;JSONLayout&quot;">​</a></h3><p><code>JSONLayout</code> 把完整 Event 组织成单行 JSON：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;level&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;info&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;time&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-06-05T10:30:00.000&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;fileLine&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;order.go:42&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;tag&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;_biz_order_create&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;order_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10001</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;msg&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;订单创建完成&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.file.layout.type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = JSONLayout</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.appender.file.layout.fileLineMaxLength</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 48</span></span></code></pre></div><p>级别、时间、调用位置、Tag、上下文信息和业务 Field 都会成为 JSON 字段；数字、布尔值、数组和对象也会保留各自的类型。因此，这种格式更适合日志采集、检索和聚合。</p><h2 id="encoder" tabindex="-1">Encoder <a class="header-anchor" href="#encoder" aria-label="Permalink to &quot;Encoder&quot;">​</a></h2><p>Layout 负责整条日志的结构，但不会分别实现每一种 Field 类型的编码逻辑。因此，具体字段怎样转换成字节，还需要由 Encoder 负责。</p><p>与两种 Layout 对应，Go-Spring 也内置了 <code>JSONEncoder</code> 和 <code>TextEncoder</code>。</p><p><code>JSONEncoder</code> 供 <code>JSONLayout</code> 使用，按照 JSON 语法编码字段：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;success&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;retry&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;tags&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;new_user&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;coupon&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]}</span></span></code></pre></div><p><code>TextEncoder</code> 则供 <code>TextLayout</code> 使用。顶层字段采用 <code>key=value</code> 形式，数组和嵌套对象则交给内部的 JSON 编码逻辑：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>success=true||retry=2||tags=[&quot;new_user&quot;,&quot;coupon&quot;]</span></span></code></pre></div><p>无论使用哪一种 Encoder，强类型 Field 都可以直接进入对应的编码方法，不需要先放进 <code>map[string]any</code>，也不需要在输出阶段重新判断类型。只有使用 <code>Any</code> 并且无法识别具体类型时，才会回退到反射编码。</p><p>Encoder 最终会把结果写向 <code>Writer</code>。Go-Spring 的 <code>Writer</code> 支持普通字节、单字节和字符串写入，因此 Layout 和 Encoder 可以边组织、边编码，不需要先构造完整的中间对象。这样一来，Layout 可以专注于整条日志的结构；Encoder 则只需要关心单个 Field 的类型和值。</p><h2 id="日志输出与格式化" tabindex="-1">日志输出与格式化 <a class="header-anchor" href="#日志输出与格式化" aria-label="Permalink to &quot;日志输出与格式化&quot;">​</a></h2><p>Layout 组织日志，Encoder 编码字段，Appender 经缓冲区写入目标。失败由 ReportError 上报，三者职责独立。</p>`,56)])])}const g=i(n,[["render",t]]);export{c as __pageData,g as default};
